async function loadDashboard(){const data=await (await fetch('/api/dashboard')).json();byId('bestSpread').textContent=data.summary.best_spread.toFixed(3)+'%';byId('markets').textContent=data.summary.markets_scanned;byId('activeStrategies').textContent=data.summary.active_strategies;byId('mode').textContent=data.summary.mode;byId('updated').textContent='жңҖиҝ‘жӣҙж–° '+new Date().toLocaleTimeString('zh-CN');byId('opportunities').innerHTML=data.opportunities.map(x=>`<tr><td class="symbol">${x.symbol}</td><td>${money(x.buy_price)}<span class="exchange">${x.buy_exchange}</span></td><td>${money(x.sell_price)}<span class="exchange">${x.sell_exchange}</span></td><td class="profit">${x.spread.toFixed(3)}%</td><td class="profit">+${x.estimated_profit.toFixed(3)}%</td><td class="funding ${x.funding>=0?'profit':''}">${x.funding>=0?'+':''}${x.funding.toFixed(4)}%</td><td>${x.updated_at}</td></tr>`).join('')}
function dailyTrendItem(item){return `<article><b>${item.symbol}</b><span class="${changeClass(item.change_24h)}">24H ${displayChange(item.change_24h)}</span><small>7D ${displayChange(item.change_7d)}</small></article>`}
function hornTimeframeLabel(item){return item.timeframe==='continue'?'е»¶з»ӯ':item.timeframe.toUpperCase()}
function hornSignalItem(item,index){return `<article><b>${index+1}</b><button class="symbol-detail-trigger" onclick="openSymbolDetail('${item.symbol}')">${item.symbol}</button><span class="horn-timeframe">${hornTimeframeLabel(item)}</span><span>з»“жһ„еҲҶ <em class="horn-score">${Number(item.score).toFixed(1)}</em></span><span>д»·ж ј <em class="${changeClass(item.price_change)}">${percent(item.price_change)}</em></span><span>OI <em class="${changeClass(item.oi_change)}">${percent(item.oi_change)}</em></span><span>дәәж•°жҜ” <em class="${changeClass(item.ratio_change)}">${percent(item.ratio_change)}</em></span><span class="${item.cvd_confirmed?'horn-cvd-confirmed':'horn-cvd-divergent'}">CVD ${item.cvd_confirmed?'зЎ®и®ӨдёҠж¶Ё':'иғҢзҰ»/жңӘзЎ®и®Ө'}</span></article>`}
function automationStatusMarkup(statuses){const values=Object.values(statuses||{});return values.length?`<div class="automation-status-row">${values.map(item=>`<span class="${item.ran_today?'ok':'warn'}"><b>${item.label}</b><em>${item.ran_today?'д»Ҡж—Ҙе·Іжү§иЎҢ':'д»Ҡж—ҘжңӘжҲҗеҠҹ'}</em><small>жңҖиҝ‘жҲҗеҠҹпјҡ${item.last_success_at||'жҡӮж— '}${item.last_error?` В· й”ҷиҜҜпјҡ${item.last_error}`:''}</small></span>`).join('')}</div>`:''}
function renderAutomationStatus(anchorId,statuses){const anchor=byId(anchorId);if(!anchor?.parentElement)return;anchor.parentElement.querySelector('.automation-status-row')?.remove();anchor.insertAdjacentHTML('beforebegin',automationStatusMarkup(statuses))}
async function loadDailyTrends(){const data=await (await fetch('/api/daily-report/trends')).json();renderAutomationStatus('dailyHorn30m',data.automation_status);byId('dailyHorn30m').innerHTML=data.horn_30m?.length?data.horn_30m.map(hornSignalItem).join(''):'<p class="empty-alert">д»Ҡж—ҘжҡӮж—  30 еҲҶй’ҹзҠ„еһӢеҖҷйҖүгҖӮ</p>';byId('dailyHorn4h').innerHTML=data.horn_4h?.length?data.horn_4h.map(hornSignalItem).join(''):'<p class="empty-alert">д»Ҡж—ҘжҡӮж—  4H зҠ„еһӢеҖҷйҖүгҖӮ</p>';byId('dailyHornContinue').innerHTML=data.horn_continue?.length?data.horn_continue.map(hornSignalItem).join(''):'<p class="empty-alert">д»Ҡж—ҘжҡӮж— зҠ„и§’е»¶з»ӯеҖҷйҖүгҖӮ</p>'}
async function loadDailyListings(){const data=await (await fetch('/api/daily-report/listings')).json();byId('dailyListings').innerHTML=data.events.length?data.events.map(item=>`<article><b>${item.symbol}</b><span class="listing-${item.type==='дёҠжһ¶'?'up':'down'}">${item.type}</span><small>${item.exchange} В· ${item.occurred_at}</small></article>`).join(''):'<p class="empty-alert">е·Іе»әз«ӢеҪ“еүҚ Binance ж°ёз»ӯеҗҲзәҰеҹәзәҝпјӣжңҖиҝ‘ 30 еӨ©жҡӮж— дёҠдёӢжһ¶еҸҳеҢ–гҖӮ</p>'}
async function loadStrategies(){const data=await (await fetch('/api/strategies')).json();byId('strategyList').innerHTML=data.map(x=>`<article class="strategy"><div><h3>${x.name}<span class="tag ${x.enabled?'':'off'}">${x.enabled?'иҝҗиЎҢдёӯ':'е·ІжҡӮеҒң'}</span></h3><p>${x.mode} В· ${x.symbol}</p></div><button onclick="toggleStrategy(${x.id})">${x.enabled?'жҡӮеҒң':'еҗҜз”Ё'}</button></article>`).join('')}
async function toggleStrategy(id){await fetch('/api/strategies/'+id,{method:'PATCH'});loadStrategies();loadDashboard()}
function openModal(){byId('modal').classList.remove('hidden')}function closeModal(){byId('modal').classList.add('hidden')}
async function saveStrategy(e){e.preventDefault();const res=await fetch('/api/strategies',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({name:byId('name').value,mode:byId('strategyMode').value,symbol:byId('symbol').value})});if(!res.ok){alert((await res.json()).error);return}e.target.reset();closeModal();loadStrategies();loadDashboard()}
function percent(value){return `${value>=0?'+':''}${Number(value).toFixed(4)}%`}
function signClass(value){return Number(value)>=0?'positive':'negative'}
function intervalClass(hours){return [1,2,4,8].includes(Number(hours))?`interval-${hours}`:'interval-other'}
function displayFunding(value){return value===null||value===undefined?'вҖ”':percent(value)}
function fundingStack(row){return `<div class="funding-stack"><span class="funding-item"><b>еҪ“еүҚ</b><span class="${signClass(row.funding_rate)}">${displayFunding(row.funding_rate)}</span></span><span class="funding-item"><b>дёҠжңҹ</b><span class="${signClass(row.funding_previous)}">${displayFunding(row.funding_previous)}</span></span><span class="funding-item"><b>24H</b><span class="${signClass(row.funding_24h)}">${displayFunding(row.funding_24h)}</span></span><span class="funding-item"><b>3D</b><span class="${signClass(row.funding_3d)}">${displayFunding(row.funding_3d)}</span></span><span class="funding-item"><b>7D</b><span class="${signClass(row.funding_7d)}">${displayFunding(row.funding_7d)}</span></span><span class="funding-item"><b>30D</b><span class="${signClass(row.funding_30d)}">${displayFunding(row.funding_30d)}</span></span></div>`}
const trendPeriods=[['change_5m','5MIN'],['change_15m','15MIN'],['change_30m','30MIN'],['change_1h','1H'],['change_12h','12H'],['change_24h','24H'],['change_3d','3D'],['change_7d','7D']];
const spotSortLabels={basis:'еҹәе·®',funding_rate:'еҪ“еүҚиө„иҙ№',funding_previous:'дёҠжңҹиө„иҙ№',funding_24h:'24H иө„иҙ№',funding_3d:'3D иө„иҙ№',funding_7d:'7D иө„иҙ№',funding_30d:'30D иө„иҙ№',change_5m:'5MIN ж¶Ёи·Ңе№…',change_15m:'15MIN ж¶Ёи·Ңе№…',change_30m:'30MIN ж¶Ёи·Ңе№…',change_1h:'1H ж¶Ёи·Ңе№…',change_12h:'12H ж¶Ёи·Ңе№…',change_24h:'24H ж¶Ёи·Ңе№…',change_3d:'3D ж¶Ёи·Ңе№…',change_7d:'7D ж¶Ёи·Ңе№…',open_spread:'ејҖе·®',close_spread:'е№іе·®'};
function changeClass(value){return value===null||value===undefined?'neutral':Number(value)>0?'positive':Number(value)<0?'negative':'neutral'}
function displayChange(value){return value===null||value===undefined?'вҖ”':percent(value)}
function trendLights(row){return `<div class="trend-lights">${trendPeriods.map(([key,label])=>`<span class="trend-light ${changeClass(row[key])}" title="${label} ${displayChange(row[key])}"><i></i><em>${label}</em></span>`).join('')}</div>`}
function priceChangeStack(row){return `<div class="change-stack">${trendPeriods.map(([key,label])=>`<span class="change-item"><b>${label}</b><span class="${changeClass(row[key])}">${displayChange(row[key])}</span></span>`).join('')}</div>`}
const exchangeIcon={Binance:'/static/exchanges/binance.png',Gate:'/static/exchanges/gate.png',Bitget:'/static/exchanges/bitget.png',Bybit:'/static/exchanges/bybit.png',OKX:'/static/exchanges/okx.png'};
function exchangeName(exchange){const icon=exchangeIcon[exchange];return `${icon?`<img class="exchange-logo" src="${icon}" alt="${exchange}">`:''}${exchange}`}
function coinglassKlineUrl(symbol){return `https://www.coinglass.com/tv/zh/Binance_${encodeURIComponent(symbol.replace('/',''))}`}
function liquidityLevel(value){const amount=Number(value||0);return amount>=10000000?'safe':amount>=5000000?'warn-light':amount>=1000000?'warn-medium':'warn-deep'}
function liquidityAmount(value){const amount=Number(value);if(!Number.isFinite(amount)||amount<=0)return 'вҖ”';return amount>=1e9?`$${(amount/1e9).toFixed(2)}B`:`$${(amount/1e6).toFixed(2)}M`}
function liquidityMetric(label,value){return `<span class="liquidity-metric ${liquidityLevel(value)}"><b>${label}</b><i>${liquidityAmount(value)}</i></span>`}
function spotLiquidity(row){return `<div class="liquidity-stack">${liquidityMetric('дәӨжҳ“йҮҸ',row.spot_volume)}</div>`}
function futuresLiquidity(row){return `<div class="liquidity-stack">${liquidityMetric('жҢҒд»“йҮҸ',row.futures_open_interest)}${liquidityMetric('дәӨжҳ“йҮҸ',row.futures_volume)}</div>`}
function spotTransferStatus(row){const chains=Array.isArray(row.transfer_networks)?row.transfer_networks:[];if(!chains.length)return `<span class="transfer-status pending">е……жҸҗеҫ…зЎ®и®Ө</span>`;const deposits=chains.filter(chain=>chain.deposit_open).length,withdrawals=chains.filter(chain=>chain.withdraw_open).length,closed=chains.filter(chain=>!chain.deposit_open||!chain.withdraw_open),payload=encodeURIComponent(JSON.stringify(chains));return `<span class="transfer-status ${closed.length?'transfer-alert':''}" data-transfer-chains="${payload}" onmouseenter="showTransferTip(this)" onmouseleave="destroyFloatingPopup()">е……${deposits}/${chains.length} В· жҸҗ${withdrawals}/${chains.length}${closed.length?` В· ${closed.length}й“ҫе…ій—ӯ`:''}</span>`}
function showTransferTip(trigger){destroyFloatingPopup();let chains=[];try{chains=JSON.parse(decodeURIComponent(trigger.dataset.transferChains||''))}catch(error){return}const open=(key)=>chains.filter(chain=>chain[key]).map(chain=>chain.name).join('/')||'е…ій—ӯ',closed=chains.filter(chain=>!chain.deposit_open||!chain.withdraw_open).map(chain=>chain.name).join('/');const popup=document.createElement('div');popup.dataset.floatingDetail='transfer';popup.className='floating-detail-popup transfer-popup';popup.innerHTML=`<div>е……еҖјпјҡ<b>${open('deposit_open')}</b></div><div>жҸҗзҺ°пјҡ<b>${open('withdraw_open')}</b>${closed?` <em>${closed}пјҲе…ій—ӯпјү</em>`:''}</div>`;document.body.appendChild(popup);positionFloatingPopup(popup,trigger)}
function spotRows(symbols){
  return symbols.map(group=>{
    const contract=group.rows[0],span=group.rows.length;
    const shared=`<td class="contract-cell" rowspan="${span}">${exchangeName('Binance')} еҗҲзәҰ</td><td rowspan="${span}">${futuresLiquidity(contract)}</td><td class="${signClass(contract.basis)} numeric" rowspan="${span}">${percent(contract.basis)}</td><td rowspan="${span}">${fundingStack(contract)}</td><td rowspan="${span}"><span class="interval-badge ${intervalClass(contract.funding_interval_hours)}">${contract.funding_interval_hours}H</span><span class="exchange">дёӢж¬Ў ${contract.next_funding_time}</span></td>`;
    return group.rows.map((row,index)=>{
      return `<tr>${index===0?`<td class="symbol" rowspan="${span}">${trendLights(contract)}<div><button class="symbol-detail-trigger ${group.delisting_announced?'delisting-symbol':''}" onclick="openSymbolDetail('${group.symbol}')">${group.symbol}</button><a class="kline-link" href="${coinglassKlineUrl(group.symbol)}" target="_blank" rel="noopener noreferrer">Kзәҝ</a></div></td><td class="price-change-cell" rowspan="${span}">${priceChangeStack(contract)}</td>`:''}<td>${spotLiquidity(row)}</td><td class="spot-cell">${exchangeName(row.long_exchange)}${spotTransferStatus(row)}</td>${index===0?shared:''}<td class="${signClass(row.open_spread)} numeric">${percent(row.open_spread)}</td><td class="${signClass(row.close_spread)} numeric">${percent(row.close_spread)}</td></tr>`;
    }).join('');
  }).join('');
}
function showMarketRefreshCountdown(seconds){clearInterval(marketRefreshCountdownTimer);let remaining=Math.max(0,Number(seconds)||0);const target=byId('spotFuturesCountdown');const render=()=>{target.textContent=remaining>0?` В· дёӢж¬ЎиЎҢжғ…еҗҢжӯҘзәҰ ${remaining} з§’`:' В· жӯЈеңЁзӯүеҫ…дёӢдёҖиҪ®иЎҢжғ…еҗҢжӯҘвҖҰ'};render();marketRefreshCountdownTimer=setInterval(()=>{remaining=Math.max(0,remaining-1);render();if(remaining===0)clearInterval(marketRefreshCountdownTimer)},1000)}
async function loadSpotFutures(manual=false){
  if(spotFuturesLoading)return;
  spotFuturesLoading=true;
  const status=byId('spotFuturesUpdated'),bnOnly=byId('binanceSpotOnly').checked;
  if(manual)status.textContent='жӯЈеңЁиҜ»еҸ–е·Ізј“еӯҳзҡ„иЎҢжғ…ж•°жҚ®вҖҰ';
  try{
    const response=await fetch('/api/spot-futures?page='+spotFuturesPage+'&binance_spot_only='+(bnOnly?'1':'0')+'&funding_interval='+encodeURIComponent(spotFundingInterval)+'&symbol='+encodeURIComponent(spotFuturesSearch)+'&sort_by='+spotSort.key+'&sort_direction='+spotSort.direction);
    const data=await response.json();
    if(!response.ok)throw new Error(data.error||'иЎҢжғ…жңҚеҠЎжҡӮдёҚеҸҜз”Ё');
    destroyFloatingPopup();spotBasisOpenings=Object.fromEntries(data.symbols.map(group=>[group.symbol,group.basis_opening]));byId('spotFuturesRows').innerHTML=data.symbols.length?spotRows(data.symbols):'<tr><td colspan="12" class="loading">жІЎжңүз¬ҰеҗҲжқЎд»¶зҡ„дәӨжҳ“еҜ№гҖӮ</td></tr>';
    spotFuturesHasData=true;
    updateSortHeaders();
    byId('pageInfo').textContent=`з¬¬ ${data.page} / ${data.pages} йЎө В· е…ұ ${data.total_symbols} дёӘеёҒз§Қ`;
    const pageSelect=byId('spotFuturesPageSelect');
    pageSelect.innerHTML=Array.from({length:data.pages},(_,index)=>`<option value="${index+1}" ${index+1===data.page?'selected':''}>${index+1}</option>`).join('');
    byId('previousPage').disabled=data.page<=1;
    byId('nextPage').disabled=data.page>=data.pages;
    const failed=Object.keys(data.errors||{});
    const detail=failed.length?failed.join('гҖҒ')+' иЎҢжғ…жҡӮдёҚеҸҜз”Ё':`е·ІеҜ№е…ЁйғЁ ${data.total_symbols} дёӘеёҒз§ҚжҺ’еәҸеҗҺеҲҶйЎө В· еҪ“еүҚжҢү${spotSortLabels[spotSort.key]}жҺ’еәҸ`;
    status.textContent=`жңҖиҝ‘жӣҙж–° ${data.updated_at} В· ${detail}`;
    showMarketRefreshCountdown(data.next_refresh_in_seconds);
  }catch(error){
    if(!spotFuturesHasData)byId('spotFuturesRows').innerHTML=`<tr><td colspan="11" class="loading">${error.message}</td></tr>`;
    status.textContent=spotFuturesHasData?'жң¬ж¬Ўжӣҙж–°еӨұиҙҘпјҢе·Ідҝқз•ҷдёҠдёҖз»„жңүж•Ҳж•°жҚ®гҖӮ':error.message;
  }finally{spotFuturesLoading=false}
}
function groupSortValue(group){const rows=group.rows;if(spotSort.key==='open_spread'||spotSort.key==='close_spread')return Math.max(...rows.map(row=>Number(row[spotSort.key])));return Number(rows[0][spotSort.key])}
function sortGroups(groups){return [...groups].sort((a,b)=>{const delta=groupSortValue(a)-groupSortValue(b);return spotSort.direction==='desc'?-delta:delta})}
function updateSortHeaders(){document.querySelectorAll('.sort-header').forEach(button=>{const active=button.dataset.sort===spotSort.key;button.classList.toggle('active',active);button.textContent=button.textContent.replace(/ [вҶ‘вҶ“]$/,'')+(active?(spotSort.direction==='desc'?' вҶ“':' вҶ‘'):'')})}
function setSpotSort(key){spotSort=spotSort.key===key?{key,direction:spotSort.direction==='desc'?'asc':'desc'}:{key,direction:'desc'};spotFuturesPage=1;updateSortHeaders();loadSpotFutures(true)}
function changeSpotFuturesPage(change){spotFuturesPage=Math.max(1,spotFuturesPage+change);loadSpotFutures(true)}
function selectSpotFuturesPage(page){spotFuturesPage=Math.max(1,Number(page)||1);loadSpotFutures(true)}
function setBinanceSpotFilter(){spotFuturesPage=1;loadSpotFutures(true)}
function setSpotFundingInterval(interval){spotFundingInterval=interval;spotFuturesPage=1;document.querySelectorAll('.spot-period-filter').forEach(button=>button.classList.toggle('active',button.dataset.spotPeriod===interval));loadSpotFutures(true)}
async function loadSymbolSuggestions(scope,query){const panel=byId(scope+'Suggestions');const normalized=query.trim();if(!normalized){panel.innerHTML='';panel.classList.add('hidden');return}const requestId=++suggestionRequest;try{const response=await fetch('/api/symbol-suggestions?q='+encodeURIComponent(normalized));const data=await response.json();if(requestId!==suggestionRequest)return;panel.innerHTML=data.items.length?data.items.map(item=>`<button type="button" class="symbol-suggestion" onclick="selectSymbolSuggestion('${scope}','${item.symbol}','${item.label}')"><span>${item.name||item.symbol.split('/')[0]}</span><small>${item.symbol}${item.live?'':' В· жҡӮж— еҪ“еүҚиЎҢжғ…'}</small></button>`).join(''):'<p class="no-suggestion">жІЎжңүеҢ№й…Қзҡ„еёҒз§Қ</p>';panel.classList.remove('hidden')}catch(error){panel.innerHTML='';panel.classList.add('hidden')}}
function selectSymbolSuggestion(scope,symbol,label){const input=byId(scope+'Search');input.value=label;byId(scope+'Suggestions').classList.add('hidden');if(scope==='spotFutures'){spotFuturesSearch=symbol;spotFuturesPage=1;loadSpotFutures(true);return}dualFuturesSearch=symbol;dualFuturesPage=1;loadDualFutures(true)}
function setSpotFuturesSearch(value){spotFuturesSearch=value.trim();spotFuturesPage=1;loadSymbolSuggestions('spotFutures',value);clearTimeout(spotFuturesSearchTimer);spotFuturesSearchTimer=setTimeout(()=>loadSpotFutures(true),180)}
function setDualFuturesSearch(value){const query=value.trim();dualFuturesSearch=query;dualFuturesPage=1;loadSymbolSuggestions('dualFutures',query);clearTimeout(dualFuturesSearchTimer);dualFuturesSearchTimer=setTimeout(()=>loadDualFutures(true),180)}
function dualDisplayPercent(value){return value===null||value===undefined?'вҖ”':percent(value)}
function dualTrendLights(group){return `<div class="trend-lights">${trendPeriods.map(([key,label])=>`<span class="trend-light ${changeClass(group['binance_'+key])}" title="${label} ${displayChange(group['binance_'+key])}"><i></i><em>${label}</em></span>`).join('')}</div>`}
function dualPriceChanges(group){return `<div class="change-stack">${trendPeriods.map(([key,label])=>`<span class="change-item"><b>${label}</b><span class="${changeClass(group['binance_'+key])}">${displayChange(group['binance_'+key])}</span></span>`).join('')}</div>`}
function dualInterval(value){return value===null||value===undefined?'вҖ”':`${value}H`}
function dualContractLeg(exchange,basis){return `<span><b>${exchangeName(exchange)}</b><i class="${changeClass(basis)}">еҹәе·® ${dualDisplayPercent(basis)}</i></span>`}
function dualFundingRates(row){return `<div class="dual-funding"><span><b>еӨҡ</b><i>${dualDisplayPercent(row.long_funding_rate)}</i><em class="interval-badge ${intervalClass(row.long_funding_interval_hours)}">${dualInterval(row.long_funding_interval_hours)}</em></span><span><b>з©ә</b><i>${dualDisplayPercent(row.short_funding_rate)}</i><em class="interval-badge ${intervalClass(row.short_funding_interval_hours)}">${dualInterval(row.short_funding_interval_hours)}</em></span></div>`}
function dualFundingDifference(row){return `<div class="${changeClass(row.funding_difference)} dual-funding-diff"><b>${dualDisplayPercent(row.funding_difference)}</b><small>${row.funding_settlement_label||'з»“з®—ж—¶й—ҙеҫ…еҗҢжӯҘ'}</small></div>`}
function dualLiquidity(row){return `<div class="liquidity-stack dual-liquidity"><span><b>еӨҡ</b>${liquidityMetric('жҢҒд»“йҮҸ',row.long_open_interest)}${liquidityMetric('дәӨжҳ“йҮҸ',row.long_volume)}</span><span><b>з©ә</b>${liquidityMetric('жҢҒд»“йҮҸ',row.short_open_interest)}${liquidityMetric('дәӨжҳ“йҮҸ',row.short_volume)}</span></div>`}
function componentMaps(row){return {long:Object.fromEntries((row.long_index_components||[]).map(item=>[item.source,item])),short:Object.fromEntries((row.short_index_components||[]).map(item=>[item.source,item]))}}
function localIndexOverlap(row){const {long,short}=componentMaps(row);return Object.keys(long).reduce((total,source)=>total+(short[source]?Math.min(Number(long[source].weight)||0,Number(short[source].weight)||0):0),0)*100}
function componentCompareRows(row){const {long,short}=componentMaps(row);return [...new Set([...Object.keys(long),...Object.keys(short)])].sort().map(source=>{const left=long[source],right=short[source],name=left?.name||right?.name,first=Number(left?.weight||0)*100,second=Number(right?.weight||0)*100;return `<article class="component-compare"><div><b>${name}</b><span>${row.long_exchange} ${first.toFixed(2)}% В· ${row.short_exchange} ${second.toFixed(2)}%</span></div><div class="component-compare-bar"><i class="long" style="width:${first.toFixed(2)}%"></i><i class="short" style="width:${second.toFixed(2)}%"></i></div></article>`}).join('')}
function dualIndexOverlap(row){const longComponents=row.long_index_components||[],shortComponents=row.short_index_components||[];if(row.index_overlap===null||row.index_overlap===undefined)return `<span class="common-index-empty">${row.index_status||'жҲҗеҲҶеҫ…еҗҢжӯҘ'}</span>`;if(!longComponents.length||!shortComponents.length)return '<span class="common-index-empty">жҢҮж•°жҲҗеҲҶдёҚеҸҜз”Ё</span>';const overlap=Math.max(0,Math.min(100,localIndexOverlap(row)));return `<div class="common-index" data-common-index-id="${row._commonIndexId}"><b class="common-index-trigger" onmouseenter="showCommonIndexTip(this)" onmouseleave="destroyFloatingPopup()">${overlap.toFixed(2)}%</b></div>`}
function dualRows(symbols){return symbols.map(group=>{const span=group.rows.length;return group.rows.map((row,index)=>`<tr class="${index===0?'dual-group-start ':index===span-1?'dual-group-end':'dual-group-body'}">${index===0?`<td class="symbol" rowspan="${span}">${dualTrendLights(group)}<div><button class="symbol-detail-trigger ${group.delisting_announced?'delisting-symbol':''}" onclick="openSymbolDetail('${group.symbol}')">${group.symbol}</button><a class="kline-link" href="${coinglassKlineUrl(group.symbol)}" target="_blank" rel="noopener noreferrer">Kзәҝ</a></div></td><td class="price-change-cell" rowspan="${span}">${dualPriceChanges(group)}</td>`:''}<td>${dualLiquidity(row)}</td><td class="dual-contract-pair">${dualContractLeg(row.long_exchange,row.long_basis)}${dualContractLeg(row.short_exchange,row.short_basis)}</td><td>${dualFundingRates(row)}</td><td>${dualFundingDifference(row)}</td><td class="${signClass(row.open_spread)} numeric">${percent(row.open_spread)}</td><td class="${signClass(row.close_spread)} numeric">${percent(row.close_spread)}</td><td>${dualIndexOverlap(row)}</td></tr>`).join('')}).join('')}
function positionFloatingPopup(popup,trigger){const rect=trigger.getBoundingClientRect(),width=Math.min(540,window.innerWidth-32),left=Math.max(16,Math.min(window.innerWidth-width-16,rect.right-width));popup.style.width=`${width}px`;popup.style.left=`${left}px`;if(rect.top<360){popup.style.top=`${rect.bottom+9}px`}else{popup.style.top=`${rect.top-9}px`;popup.style.transform='translateY(-100%)'}}
function destroyFloatingPopup(){document.querySelector('[data-floating-detail]')?.remove()}
function showCommonIndexTip(trigger){destroyFloatingPopup();const row=dualIndexRows.get(trigger.closest('.common-index')?.dataset.commonIndexId);if(!row)return;const overlap=Math.max(0,Math.min(100,localIndexOverlap(row))),popup=document.createElement('div'),path=`${row.long_exchange} вҶ’ ${row.short_exchange}`;popup.dataset.floatingDetail='common-index';popup.className='floating-detail-popup common-index-popup';popup.innerHTML=`<header><span><i class="index-key long"></i>${exchangeName(row.long_exchange)}</span><b class="index-path">${path}</b><span><i class="index-key short"></i>${exchangeName(row.short_exchange)}</span></header><div class="component-compare-list">${componentCompareRows(row)}</div><div class="common-index-bar"><i style="width:${overlap.toFixed(2)}%"></i></div><small>е…ұеҗҢжҲҗеҲҶжқғйҮҚ ${overlap.toFixed(2)}%</small>`;document.body.appendChild(popup);positionFloatingPopup(popup,trigger)}
function showDualRefreshCountdown(seconds){clearInterval(dualMarketRefreshCountdownTimer);let remaining=Math.max(0,Number(seconds)||0),target=byId('dualFuturesCountdown');const render=()=>{target.textContent=remaining>0?` В· дёӢж¬ЎиЎҢжғ…еҗҢжӯҘзәҰ ${remaining} з§’`:' В· жӯЈеңЁзӯүеҫ…дёӢдёҖиҪ®иЎҢжғ…еҗҢжӯҘвҖҰ'};render();dualMarketRefreshCountdownTimer=setInterval(()=>{remaining=Math.max(0,remaining-1);render();if(remaining===0)clearInterval(dualMarketRefreshCountdownTimer)},1000)}
function updateDualSortHeaders(){document.querySelectorAll('.dual-sort-header').forEach(button=>{const active=button.dataset.dualSort===dualSort.key;button.classList.toggle('active',active);button.textContent=button.textContent.replace(/ [вҶ•вҶ“вҶ‘]$/,'')+(active?(dualSort.direction==='desc'?' вҶ“':' вҶ‘'):'')})}
function setDualSort(key){dualSort=dualSort.key===key?{key,direction:dualSort.direction==='desc'?'asc':'desc'}:{key,direction:'desc'};dualFuturesPage=1;updateDualSortHeaders();loadDualFutures(true)}
function changeDualFuturesPage(change){dualFuturesPage=Math.max(1,dualFuturesPage+change);loadDualFutures(true)}
function selectDualFuturesPage(page){dualFuturesPage=Math.max(1,Number(page)||1);loadDualFutures(true)}
function renderDualFuturesShell(){const target=byId('dual-futures');target.innerHTML=`<div class="strategy-hero"><p class="eyebrow">STRATEGY 01 В· FUTURES / FUTURES</p><h2>жңҹеӨҡжңҹз©әеҘ—еҲ©</h2><p>еӣәе®ҡзӣ‘жҺ§ Bybit вҶ’ BinanceгҖҒOKX вҶ’ Binance дёҺ Bybit вҶ’ OKX дёүжқЎж°ёз»ӯеҗҲзәҰеҜ№еҶІи·Ҝеҫ„гҖӮеҒҡеӨҡдәӨжҳ“жүҖе§Ӣз»ҲеңЁе·ҰпјҢеҒҡз©әдәӨжҳ“жүҖе§Ӣз»ҲеңЁеҸіпјӣи¶ӢеҠҝдёҺж¶Ёи·Ңе№…з»ҹдёҖеҸӮиҖғ Binance еҗҲзәҰгҖӮ</p><span class="mode-pill">еҗҺеҸ°жҜҸ 5 з§’жӣҙж–° В· йЎөйқўдёҚй—ӘзғҒ</span></div><div class="panel"><div class="panel-title"><div><p class="eyebrow">LIVE FUTURES / FUTURES SCANNER</p><h2>жңҹеӨҡжңҹз©әжңәдјҡ</h2></div><div class="spot-actions"><div class="search-suggest-wrap"><label class="search-control"><span>вҢ•</span><input id="dualFuturesSearch" type="search" autocomplete="off" placeholder="жҗңзҙўеёҒз§ҚпјҢдҫӢеҰӮ BTC" oninput="setDualFuturesSearch(this.value)"></label><div id="dualFuturesSuggestions" class="symbol-suggestions hidden"></div></div><button onclick="loadDualFutures(true)">вҶ» еҲ·ж–°ж•°жҚ®</button></div></div><div class="table-wrap"><table><thead><tr><th>дәӨжҳ“еҜ№ / и¶ӢеҠҝ</th><th><div class="change-header"><span>ж¶Ёи·Ңе№…</span><div class="change-sort-controls"><button class="dual-sort-header" data-dual-sort="binance_change_5m" onclick="setDualSort('binance_change_5m')">5MIN</button><button class="dual-sort-header" data-dual-sort="binance_change_15m" onclick="setDualSort('binance_change_15m')">15MIN</button><button class="dual-sort-header" data-dual-sort="binance_change_30m" onclick="setDualSort('binance_change_30m')">30MIN</button><button class="dual-sort-header" data-dual-sort="binance_change_1h" onclick="setDualSort('binance_change_1h')">1H</button><button class="dual-sort-header" data-dual-sort="binance_change_12h" onclick="setDualSort('binance_change_12h')">12H</button><button class="dual-sort-header" data-dual-sort="binance_change_24h" onclick="setDualSort('binance_change_24h')">24H</button><button class="dual-sort-header" data-dual-sort="binance_change_3d" onclick="setDualSort('binance_change_3d')">3D</button><button class="dual-sort-header" data-dual-sort="binance_change_7d" onclick="setDualSort('binance_change_7d')">7D</button></div></div></th><th><button class="dual-sort-header" data-dual-sort="binance_basis" onclick="setDualSort('binance_basis')">еҗҲзәҰи·Ҝеҫ„ / еҹәе·®</button></th><th>дәӨжҳ“жүҖиө„иҙ№ / е‘Ёжңҹ</th><th><button class="dual-sort-header" data-dual-sort="funding_difference" onclick="setDualSort('funding_difference')">дёӢжңҹиө„иҙ№е·®</button></th><th><button class="dual-sort-header" data-dual-sort="open_spread" onclick="setDualSort('open_spread')">ејҖе·® вҶ“</button></th><th><button class="dual-sort-header" data-dual-sort="close_spread" onclick="setDualSort('close_spread')">е№іе·®</button></th><th>е…ұжҢҮ</th></tr></thead><tbody id="dualFuturesRows"><tr><td colspan="8" class="loading">жӯЈеңЁиҝһжҺҘдёүе®¶дәӨжҳ“жүҖзҡ„е…¬ејҖеҗҲзәҰиЎҢжғ…вҖҰ</td></tr></tbody></table></div><div class="pagination"><button id="dualPreviousPage" onclick="changeDualFuturesPage(-1)">вҶҗ дёҠдёҖйЎө</button><label class="page-picker">и·іиҮі <select id="dualFuturesPageSelect" onchange="selectDualFuturesPage(this.value)"></select> йЎө</label><span id="dualPageInfo">з¬¬ 1 йЎө</span><button id="dualNextPage" onclick="changeDualFuturesPage(1)">дёӢдёҖйЎө вҶ’</button></div><p class="data-status"><span id="dualFuturesUpdated"></span><span id="dualFuturesCountdown" class="refresh-countdown"></span></p></div>`}
async function loadDualFutures(manual=false){if(dualFuturesLoading||!byId('dualFuturesRows'))return;dualFuturesLoading=true;const status=byId('dualFuturesUpdated');if(manual)status.textContent='жӯЈеңЁиҜ»еҸ–еҗҺеҸ°е·Ізј“еӯҳзҡ„еҗҲзәҰиЎҢжғ…вҖҰ';try{const response=await fetch('/api/dual-futures?page='+dualFuturesPage+'&symbol='+encodeURIComponent(dualFuturesSearch)+'&sort_by='+dualSort.key+'&sort_direction='+dualSort.direction);const data=await response.json();if(!response.ok)throw new Error(data.error||'жңҹеӨҡжңҹз©әиЎҢжғ…жҡӮж—¶ж— жі•иҜ»еҸ–');destroyFloatingPopup();dualBasisOpenings=Object.fromEntries(data.symbols.map(group=>[group.symbol,group.basis_opening]));dualIndexRows=new Map();data.symbols.forEach(group=>group.rows.forEach(row=>{row._commonIndexId=`${group.symbol}|${row.long_exchange}|${row.short_exchange}`;dualIndexRows.set(row._commonIndexId,row)}));byId('dualFuturesRows').innerHTML=data.symbols.length?dualRows(data.symbols):'<tr><td colspan="10" class="loading">жІЎжңүз¬ҰеҗҲжқЎд»¶зҡ„еҗҲзәҰи·Ҝеҫ„гҖӮ</td></tr>';dualFuturesHasData=true;updateDualSortHeaders();byId('dualPageInfo').textContent=`з¬¬ ${data.page} / ${data.pages} йЎө В· е…ұ ${data.total_symbols} дёӘеёҒз§Қ`;const pageSelect=byId('dualFuturesPageSelect');pageSelect.innerHTML=Array.from({length:data.pages},(_,index)=>`<option value="${index+1}" ${index+1===data.page?'selected':''}>${index+1}</option>`).join('');byId('dualPreviousPage').disabled=data.page<=1;byId('dualNextPage').disabled=data.page>=data.pages;status.textContent=`жңҖиҝ‘жӣҙж–° ${data.updated_at} В· е·ІеҜ№е…ЁйғЁ ${data.total_symbols} дёӘеёҒз§ҚжҺ’еәҸ В· еҪ“еүҚжҢү ${dualSort.key} жҺ’еәҸ`;showDualRefreshCountdown(data.next_refresh_in_seconds)}catch(error){if(!dualFuturesHasData)byId('dualFuturesRows').innerHTML=`<tr><td colspan="10" class="loading">${error.message}</td></tr>`;status.textContent=dualFuturesHasData?'жң¬ж¬Ўжӣҙж–°еӨұиҙҘпјҢе·Ідҝқз•ҷдёҠдёҖз»„жңүж•Ҳж•°жҚ®гҖӮ':error.message}finally{dualFuturesLoading=false}}
function addDualLiquidityHeader(){const table=byId('dual-futures')?.querySelector('table');if(!table)return;const header=table.querySelector('thead tr');const changeHeader=header?.querySelector('.change-header')?.closest('th');if(changeHeader&&!header.querySelector('.liquidity-column')){const column=document.createElement('th');column.className='liquidity-column';column.textContent='жөҒеҠЁжҖ§';changeHeader.insertAdjacentElement('afterend',column)}table.querySelectorAll('td[colspan="8"]').forEach(cell=>cell.colSpan=9)}
function addDualBasisSortControls(){const button=byId('dual-futures')?.querySelector('[data-dual-sort="binance_basis"]');if(!button||button.closest('.basis-sort-controls'))return;const wrapper=document.createElement('div');wrapper.className='basis-sort-controls';wrapper.innerHTML='<span>еҗҲзәҰеҹәе·®</span><div><button class="dual-sort-header" data-dual-sort="binance_basis" onclick="setDualSort(\'binance_basis\')">BN</button><button class="dual-sort-header" data-dual-sort="bybit_basis" onclick="setDualSort(\'bybit_basis\')">BY</button><button class="dual-sort-header" data-dual-sort="okx_basis" onclick="setDualSort(\'okx_basis\')">OK</button></div>';button.replaceWith(wrapper)}
function alertLabel(type){return type==='futures_pump'?'еҗҲзәҰжӢүеҚҮ':type==='spot_pump'?'зҺ°иҙ§жӢүеҚҮ':type==='rapid_spread'?'ејҖе·®йҖҹеҸҳ':type==='rapid_basis'?'еҹәе·®йҖҹеҸҳ':type==='dual_spread_threshold'?'ејҖе·®ејӮеҠЁ':type==='dual_basis_threshold'?'BN еҹәе·®ејӮеҠЁ':'еҹәе·®ејӮеҠЁ'}
function alertClass(type){return type==='futures_pump'?'futures':type==='spot_pump'?'spot':type==='rapid_spread'?'rapid-spread':type==='rapid_basis'?'rapid-basis':'basis'}
function alertMetric(value){return value===null||value===undefined?'вҖ”':percent(value)}
function strategyLabel(strategy){return strategy==='futures_futures'?'жңҹеӨҡжңҹз©ә':'зҺ°еӨҡжңҹз©ә'}
function alertExchangeLeg(exchange,market,interval){return `<span>${exchangeName(exchange)} ${market}${interval?` <em class="interval-badge ${intervalClass(interval)}">${interval}H</em>`:''}</span>`}
function alertExchangePair(item){return `<div class="alert-exchange-pair">${alertExchangeLeg(item.long_exchange,item.long_market,item.long_interval)}<b>вҶ’</b>${alertExchangeLeg(item.short_exchange,item.short_market,item.short_interval)}</div>`}
function toggleTips(){byId('tipsPanel').classList.toggle('collapsed')}
function updateAlarmSoundButton(){const button=byId('alarmSoundToggle');if(button){button.textContent=alarmSoundEnabled?'жҠҘиӯҰеЈ°йҹіпјҡејҖеҗҜ':'жҠҘиӯҰеЈ°йҹіпјҡйқҷйҹі';button.classList.toggle('enabled',alarmSoundEnabled)}}
async function playAlarmSound(force=false){if(!force&&!alarmSoundEnabled)return;try{alarmAudioContext=alarmAudioContext||new (window.AudioContext||window.webkitAudioContext)();if(alarmAudioContext.state==='suspended')await alarmAudioContext.resume();Array.from({length:12},(_,index)=>index*.125).forEach((offset,index)=>{const oscillator=alarmAudioContext.createOscillator(),gain=alarmAudioContext.createGain();oscillator.type='square';oscillator.frequency.value=index%2?880:1175;gain.gain.setValueAtTime(.0001,alarmAudioContext.currentTime+offset);gain.gain.exponentialRampToValueAtTime(.55,alarmAudioContext.currentTime+offset+.01);gain.gain.exponentialRampToValueAtTime(.0001,alarmAudioContext.currentTime+offset+.105);oscillator.connect(gain).connect(alarmAudioContext.destination);oscillator.start(alarmAudioContext.currentTime+offset);oscillator.stop(alarmAudioContext.currentTime+offset+.11)})}catch(error){}}
function toggleAlarmSound(){alarmSoundEnabled=!alarmSoundEnabled;localStorage.setItem('arbi-alarm-sound',alarmSoundEnabled?'on':'off');updateAlarmSoundButton();if(alarmSoundEnabled)playAlarmSound()}
function testAlarmSound(){playAlarmSound(true)}
function alertDeathMarkup(item){const expiresAt=Date.now()+Math.max(0,Number(item.remaining_seconds)||0)*1000;return `<small class="alert-death" data-alert-expires="${expiresAt}">${item.created_at} В· еү©дҪҷ ${item.remaining_seconds}s</small>`}
function updateAlertCountdowns(){let expired=false;document.querySelectorAll('.alert-death').forEach(node=>{const remaining=Math.max(0,Math.ceil((Number(node.dataset.alertExpires)-Date.now())/1000));node.textContent=node.textContent.replace(/еү©дҪҷ \d+s$/,`еү©дҪҷ ${remaining}s`);if(remaining===0)expired=true});if(expired)loadAlerts(true)}
function startAlertCountdown(){clearInterval(alertCountdownTimer);updateAlertCountdowns();alertCountdownTimer=setInterval(updateAlertCountdowns,1000)}
function alertTimelineNode(item){return `<li class="alert-timeline-node ${alertClass(item.type)}"><i></i><div><time>${item.created_at}</time><b>${strategyLabel(item.strategy)} В· ${alertLabel(item.type)}</b>${alertExchangePair(item)}<span>ејҖе·® <em class="${changeClass(item.open_spread)}">${alertMetric(item.open_spread)}</em> В· еҹәе·® <em class="${changeClass(item.basis)}">${alertMetric(item.basis)}</em></span></div></li>`}
function alertDetailCard(group){const latest=group.latest;return `<article class="alert-detail-card ${alertClass(latest.type)}"><header><div><div class="alert-card-title"><h4>${group.symbol}</h4><span class="strategy-badge">${group.alert_count} ж¬ЎжҠҘиӯҰ</span></div><span class="alert-latest-label">жңҖиҝ‘пјҡ${strategyLabel(latest.strategy)} В· ${alertLabel(latest.type)} В· ${latest.created_at}</span></div><div class="alert-values"><span>ејҖе·® <b class="${changeClass(latest.open_spread)}">${alertMetric(latest.open_spread)}</b></span><span>еҹәе·® <b class="${changeClass(latest.basis)}">${alertMetric(latest.basis)}</b></span></div></header>${alertExchangePair(latest)}<ol class="alert-timeline">${group.timeline.map(alertTimelineNode).join('')}</ol></article>`}
function alertMovePeaks(group){const peaks=group.move_peaks||{};return `<div class="alert-move-peaks"><span>ејҖе·®еі°еҖј <b class="${changeClass(peaks.open_spread)}">${alertMetric(peaks.open_spread)}</b></span><span>еҹәе·®еі°еҖј <b class="${changeClass(peaks.basis)}">${alertMetric(peaks.basis)}</b></span></div>`}
function renderAlertMasterDetail(groups){latestAlertGroups=groups;if(!groups.some(group=>group.symbol===selectedAlertSymbol))selectedAlertSymbol=groups[0]?.symbol||'';const selected=groups.find(group=>group.symbol===selectedAlertSymbol);byId('alertEvents').innerHTML=groups.length?`<div class="alert-symbol-list">${groups.map(group=>{const latest=group.latest;return `<button class="alert-symbol-option ${group.symbol===selectedAlertSymbol?'active':''} ${alertClass(latest.type)}" onclick="selectAlertSymbol('${group.symbol}')"><b>${group.symbol}</b><span>${latest.created_at} В· ${alertLabel(latest.type)}</span>${alertMovePeaks(group)}<small>${group.alert_count} ж¬Ў В· жңҖиҝ‘ејҖе·® ${alertMetric(latest.open_spread)} В· жңҖиҝ‘еҹәе·® ${alertMetric(latest.basis)}</small></button>`}).join('')}</div><div class="alert-detail-pane">${alertDetailCard(selected)}</div>`:'<p class="empty-alert">жҡӮж—¶жІЎжңүзЎ®и®ӨеҗҺзҡ„жҠҘиӯҰгҖӮ</p>'}
function selectAlertSymbol(symbol){selectedAlertSymbol=symbol;renderAlertMasterDetail(latestAlertGroups)}
async function loadAlerts(force=false){try{const data=await (await fetch('/api/alerts')).json(),activeEvents=data.active_events||[];const signature=activeEvents.map(item=>`${item.symbol}-${item.type}-${item.open_spread}-${item.basis}-${item.created_at}`).join('|');const hasNewAlert=alertsInitialized&&signature!==alertSignature&&activeEvents.length>0;if(!force&&signature===alertSignature)return;alertSignature=signature;renderAlertMasterDetail(data.events||[]);byId('basisTracking').innerHTML=data.basis_tracking.length?data.basis_tracking.map(item=>`<article class="alert-item basis"><div class="alert-card-title"><h4>${item.symbol}</h4><span class="strategy-badge">${strategyLabel(item.strategy)} В· еҹәе·®иҝҪиёӘ</span></div><p class="tracking-max">жңҖеӨ§ ${percent(item.max_basis)}</p><div class="meta"><span>е·Іи®°еҪ•иҮі ${item.last_level.toFixed(1)}%</span><span>жңҖеӨ§ж—¶й—ҙ ${item.max_at}</span></div></article>`).join(''):'<p class="empty-alert">жҡӮж— жӯЈеңЁиҝҪиёӘзҡ„еҹәе·®жү©еұ•гҖӮ</p>';byId('tipsCount').textContent=activeEvents.length;byId('tipsItems').innerHTML=activeEvents.length?activeEvents.map(item=>`<article class="tips-item ${alertClass(item.type)}"><b>${item.symbol} В· ${strategyLabel(item.strategy)} В· ${alertLabel(item.type)}</b>${alertExchangePair(item)}<span>ејҖе·® ${alertMetric(item.open_spread)} В· еҹәе·® ${alertMetric(item.basis)}</span>${alertDeathMarkup(item)}</article>`).join(''):'<p class="empty-alert">еҪ“еүҚжІЎжңүеӨ„дәҺ 120 з§’жңүж•Ҳжңҹзҡ„жҠҘиӯҰгҖӮ</p>';startAlertCountdown();alertsInitialized=true;if(hasNewAlert)playAlarmSound()}catch(error){byId('alertEvents').innerHTML='<p class="empty-alert">жҠҘиӯҰи®°еҪ•жҡӮж—¶ж— жі•иҜ»еҸ–гҖӮ</p>';byId('tipsItems').innerHTML='<p class="empty-alert">жҠҘиӯҰжҡӮж—¶ж— жі•иҜ»еҸ–гҖӮ</p>'}}
function tokenHedgeList(items){return `<ul>${(items||[]).map(item=>`<li>${item}</li>`).join('')}</ul>`}
function tokenHedgeSources(items){return `<div class="token-hedge-sources">${(items||[]).map(item=>`<a target="_blank" rel="noopener noreferrer" href="${item.url}">${item.label}</a>`).join('')}</div>`}
async function loadTokenHedgeProfiles(){const target=byId('tokenHedgeProfiles');if(!target)return;target.innerHTML='<p class="loading">жӯЈеңЁиҜ»еҸ–д»ЈеёҒжЎЈжЎҲвҖҰ</p>';try{const data=await (await fetch('/api/token-hedge/profiles')).json();target.innerHTML=data.profiles?.length?data.profiles.map(item=>`<article class="token-hedge-card ${item.risk_level==='жһҒй«ҳ'?'extreme':'high'}"><div class="token-hedge-head"><div><p class="eyebrow">${item.status}</p><h3>${item.symbol}<span>${item.name}</span></h3></div><b>${item.risk_level}</b></div><section><h4>е®ҳж–№е·ІзЎ®и®Ө</h4>${tokenHedgeList(item.official_facts)}</section><section class="token-hedge-thesis"><h4>зӣҳеҸЈжҺЁжј”</h4><p>${item.market_thesis}</p></section><section><h4>зӣҜзӣҳи§„еҲҷ</h4>${tokenHedgeList(item.watch_rules)}</section>${tokenHedgeSources(item.sources)}</article>`).join(''):'<p class="empty-alert">жҡӮж— д»ЈеёҒжЎЈжЎҲгҖӮ</p>'}catch(error){target.innerHTML='<p class="empty-alert">д»ЈеёҒжЎЈжЎҲжҡӮж—¶ж— жі•иҜ»еҸ–гҖӮ</p>'}}
function isDailyView(viewId){return ['daily-trends','daily-thoughts','daily-listings'].includes(viewId)}
function updateSidebarSubnav(viewId){document.querySelectorAll('aside .nav-sub').forEach(item=>item.classList.add('hidden'));if(viewId==='spot-futures')document.querySelector('aside .spot-period-nav')?.classList.remove('hidden');if(isDailyView(viewId))document.querySelector('aside .daily-nav')?.classList.remove('hidden')}
function updateSidebarActive(link,viewId){document.querySelectorAll('nav a[data-view]').forEach(item=>{const parentSpot=item.dataset.subnav==='spot-period-nav'&&viewId==='spot-futures';const parentDaily=item.dataset.subnav==='daily-nav'&&isDailyView(viewId);item.classList.toggle('active',item===link||parentSpot||parentDaily)})}
document.querySelectorAll('nav a[data-view]').forEach(link=>link.addEventListener('click',event=>{event.preventDefault();const viewId=link.dataset.view;document.querySelectorAll('.view').forEach(view=>view.classList.toggle('active',view.id===viewId));updateSidebarActive(link,viewId);updateSidebarSubnav(viewId);if(viewId==='alerts')loadAlerts(true);if(viewId==='daily-trends')loadDailyTrends();if(viewId==='daily-listings')loadDailyListings();if(viewId==='token-hedge')loadTokenHedgeProfiles();if(viewId==='funding-trend')loadFundingTrend();window.location.hash=viewId}));
function basisOpeningMarkup(opening,key){if(!opening)return '<span class="basis-opening-empty">вҖ”</span>';basisOpeningDetails.set(key,opening);return `<div class="basis-opening"><b data-basis-opening-id="${key}" onmouseenter="showBasisOpeningTip(this)" onmouseleave="destroyFloatingPopup()">жү“ејҖ Г— ${opening.open_count||1}</b><span>${percent(opening.opened_basis)}</span><small>жңҖиҝ‘ ${opening.opened_at}</small></div>`}
function showBasisOpeningTip(trigger){destroyFloatingPopup();const opening=basisOpeningDetails.get(trigger.dataset.basisOpeningId);if(!opening)return;const popup=document.createElement('div');popup.dataset.floatingDetail='basis-opening';popup.className='floating-detail-popup basis-opening-popup';popup.innerHTML=`<strong>еҹәе·®жңҖиҝ‘жү“ејҖ</strong><dl><div><dt>йҰ–ж¬Ўи¶ҠйҳҲ</dt><dd>${percent(opening.opened_basis)} В· ${opening.opened_at}</dd></div><div><dt>иҝ‘жңҹжңҖеӨ§</dt><dd>${percent(opening.max_basis)} В· ${opening.max_at}</dd></div><div><dt>жү“ејҖж¬Ўж•°</dt><dd>${opening.open_count||1} ж¬Ў</dd></div></dl><small>йҰ–ж¬Ўз»қеҜ№еҖји¶ҠиҝҮ 1%пјҢжҜҸжү©еӨ§ 0.2% и®ЎдёҖж¬Ў</small>`;document.body.appendChild(popup);positionFloatingPopup(popup,trigger)}
function addBasisOpeningCells(targetId,prefix,openings){const target=byId(targetId);if(!target)return;target.querySelectorAll(`tr.${prefix}-group-start`).forEach(row=>{if(row.querySelector('.basis-opening-cell'))return;const symbol=row.querySelector('td.symbol>div:last-of-type>span')?.textContent;if(!symbol)return;const span=Number(row.querySelector('td.symbol')?.rowSpan)||1;const key=`${prefix}:${symbol}`;row.insertAdjacentHTML('beforeend',`<td class="basis-opening-cell" rowspan="${span}">${basisOpeningMarkup(openings[symbol],key)}</td>`)})}
function addBasisOpeningHeaders(){const spotHeader=byId('spot-futures')?.querySelector('table thead tr');if(spotHeader&&!spotHeader.querySelector('.basis-opening-column'))spotHeader.insertAdjacentHTML('beforeend','<th class="basis-opening-column">еҹәе·®жү“ејҖ</th>');const dualHeader=byId('dual-futures')?.querySelector('table thead tr');if(dualHeader&&!dualHeader.querySelector('.basis-opening-column'))dualHeader.insertAdjacentHTML('beforeend','<th class="basis-opening-column">еҹәе·®жү“ејҖ</th>')}
function applyGroupFrameClasses(targetId,prefix){const target=byId(targetId);if(!target)return;let rowsRemaining=0;[...target.querySelectorAll('tr')].forEach(row=>{row.classList.remove(`${prefix}-group-start`,`${prefix}-group-body`,`${prefix}-group-end`);const symbolCell=row.querySelector('td.symbol[rowspan]');if(symbolCell){rowsRemaining=Number(symbolCell.rowSpan)||1;row.classList.add(`${prefix}-group-start`);if(rowsRemaining===1)row.classList.add(`${prefix}-group-end`)}else if(rowsRemaining===1){row.classList.add(`${prefix}-group-end`)}else if(rowsRemaining>1){row.classList.add(`${prefix}-group-body`)}rowsRemaining=Math.max(0,rowsRemaining-1)});addBasisOpeningCells(targetId,prefix,prefix==='spot'?spotBasisOpenings:dualBasisOpenings);const dividerClass=`${prefix}-group-divider`,columns=prefix==='spot'?12:10;if(!target.querySelector(`.${dividerClass}`))target.querySelectorAll(`tr.${prefix}-group-end`).forEach(row=>row.insertAdjacentHTML('afterend',`<tr class="${dividerClass}" aria-hidden="true"><td colspan="${columns}"></td></tr>`))}
function installGroupFrameObservers(){[['dualFuturesRows','dual'],['spotFuturesRows','spot']].forEach(([targetId,prefix])=>{const target=byId(targetId);if(!target)return;new MutationObserver(()=>applyGroupFrameClasses(targetId,prefix)).observe(target,{childList:true});applyGroupFrameClasses(targetId,prefix)})}
async function loadDailyListings(){const data=await (await fetch('/api/daily-report/listings')).json(),groups={};renderAutomationStatus('dailyListings',data.automation_status);data.events.forEach(item=>(groups[item.exchange]??=[]).push(item));byId('dailyListings').innerHTML=Object.keys(groups).length?Object.entries(groups).map(([exchange,items])=>`<section class="listing-exchange"><h3>${exchange}</h3>${items.map(item=>`<article><b>${item.symbol}</b><span class="listing-${item.type==='дёҠжһ¶'?'up':'down'}">${item.type}</span><small>е…¬е‘Ҡж”¶еҪ•пјҡ${item.occurred_at}${item.effective_at?` В· жү§иЎҢж—¶й—ҙпјҡ${item.effective_at}`:' В· жү§иЎҢж—¶й—ҙеҫ…и§Јжһҗ'}${item.title?` В· ${item.title}`:''}</small></article>`).join('')}</section>`).join(''):'<p class="empty-alert">жҡӮж— е·Іе…Ҙеә“зҡ„дәӨжҳ“жүҖе…¬е‘ҠгҖӮ</p>'}
async function loadSimpleThinking(){const section=byId('thinking');if(!section)return;let target=byId('simpleThinkingList');if(!target){section.insertAdjacentHTML('beforeend','<div class="panel simple-thinking"><div id="simpleThinkingList" class="thinking-columns"></div></div>');target=byId('simpleThinkingList')}const thinkingInterval=interval=>interval?`<em class="interval-badge ${intervalClass(interval)}">${interval}H</em>`:'',thinkingLeg=(side,exchange,openInterest,volume,isSpot,interval)=>`<div class="thinking-leg ${side==='еҒҡеӨҡ'?'long':'short'}"><b>${side}</b><span class="thinking-exchange">${exchangeName(exchange)}${thinkingInterval(interval)}</span><div class="thinking-metrics">${isSpot?liquidityMetric('дәӨжҳ“йҮҸ',volume):`${liquidityMetric('жҢҒд»“йҮҸ',openInterest)}${liquidityMetric('дәӨжҳ“йҮҸ',volume)}`}</div></div>`,thinkingFunding=item=>`<div class="thinking-funding"><span>еҪ“еүҚ <b class="${changeClass(item.funding_current)}">${percent(item.funding_current)}</b></span><span>дёҠжңҹ <b class="${changeClass(item.funding_previous)}">${percent(item.funding_previous)}</b></span><span>24H <b class="${changeClass(item.funding_24h)}">${percent(item.funding_24h)}</b></span><span>3D <b class="${changeClass(item.funding_3d)}">${percent(item.funding_3d)}</b></span></div>`,data=await (await fetch('/api/arbitrage-thinking/simple')).json(),render=items=>items.map(item=>`<article><b><button class="symbol-detail-trigger" onclick="openSymbolDetail('${item.symbol}')">${item.symbol}</button></b><span class="positive">ејҖе·® ${percent(item.open_spread)} В· е№іе·® ${percent(item.close_spread)}</span>${thinkingFunding(item)}<div class="thinking-liquidity">${thinkingLeg('еҒҡеӨҡ',item.long_exchange,item.long_open_interest,item.long_volume,item.long_is_spot,item.long_interval)}${thinkingLeg('еҒҡз©ә',item.short_exchange,item.short_open_interest,item.short_volume,item.short_is_spot,item.short_interval)}</div></article>`).join('')||'<p class="empty-alert">еҪ“еүҚжІЎжңүз¬ҰеҗҲжқЎд»¶зҡ„еёҒз§ҚгҖӮ</p>';target.innerHTML=`<section><h3>зҺ°еӨҡжңҹз©ә</h3>${render(data.spot_simple)}</section><section><h3>жңҹеӨҡжңҹз©ә</h3>${render(data.dual_simple)}</section>`}
let simpleThinkingSort='open_spread',simpleThinkingDirection='desc',simpleThinkingCache=null;
const simpleThinkingSortOptions=[['open_spread','ејҖе·®'],['close_spread','е№іе·®'],['funding_current','еҪ“еүҚиө„иҙ№'],['funding_previous','дёҠжңҹиө„иҙ№'],['funding_24h','24Hиө„иҙ№'],['funding_3d','3Dиө„иҙ№']];
