function renderSimpleThinkingSortControls(){return `<div class="thinking-sort-controls"><span>жҺ’еәҸ</span>${simpleThinkingSortOptions.map(([key,label])=>`<button class="${simpleThinkingSort===key?'active':''}" onclick="setSimpleThinkingSort('${key}')">${label}${simpleThinkingSort===key?` ${simpleThinkingDirection==='desc'?'вҶ“':'вҶ‘'}`:''}</button>`).join('')}</div>`}
async function loadSimpleThinking(refresh=true){const section=byId('thinking');if(!section)return;let target=byId('simpleThinkingList');if(!target){section.insertAdjacentHTML('beforeend','<div class="panel simple-thinking"><div id="simpleThinkingList" class="thinking-columns"></div></div>');target=byId('simpleThinkingList')}const thinkingInterval=interval=>interval?`<em class="interval-badge ${intervalClass(interval)}">${interval}H</em>`:'',thinkingLeg=(side,exchange,openInterest,volume,isSpot,interval)=>`<div class="thinking-leg ${side==='еҒҡеӨҡ'?'long':'short'}"><b>${side}</b><span class="thinking-exchange">${exchangeName(exchange)}${thinkingInterval(interval)}</span><div class="thinking-metrics">${isSpot?liquidityMetric('дәӨжҳ“йҮҸ',volume):`${liquidityMetric('жҢҒд»“йҮҸ',openInterest)}${liquidityMetric('дәӨжҳ“йҮҸ',volume)}`}</div></div>`,thinkingFunding=item=>`<div class="thinking-funding"><span>еҪ“еүҚ <b class="${changeClass(item.funding_current)}">${percent(item.funding_current)}</b></span><span>дёҠжңҹ <b class="${changeClass(item.funding_previous)}">${percent(item.funding_previous)}</b></span><span>24H <b class="${changeClass(item.funding_24h)}">${percent(item.funding_24h)}</b></span><span>3D <b class="${changeClass(item.funding_3d)}">${percent(item.funding_3d)}</b></span></div>`;if(refresh||!simpleThinkingCache)simpleThinkingCache=await (await fetch('/api/arbitrage-thinking/simple')).json();const sorted=items=>[...(items||[])].sort((a,b)=>(simpleThinkingSortValue(a,simpleThinkingSort)-simpleThinkingSortValue(b,simpleThinkingSort))*(simpleThinkingDirection==='desc'?-1:1)),render=items=>sorted(items).map(item=>`<article><b><button class="symbol-detail-trigger" onclick="openSymbolDetail('${item.symbol}')">${item.symbol}</button></b><span class="positive">ејҖе·® ${percent(item.open_spread)} В· е№іе·® ${percent(item.close_spread)}</span>${thinkingFunding(item)}<div class="thinking-liquidity">${thinkingLeg('еҒҡеӨҡ',item.long_exchange,item.long_open_interest,item.long_volume,item.long_is_spot,item.long_interval)}${thinkingLeg('еҒҡз©ә',item.short_exchange,item.short_open_interest,item.short_volume,item.short_is_spot,item.short_interval)}</div></article>`).join('')||'<p class="empty-alert">еҪ“еүҚжІЎжңүз¬ҰеҗҲжқЎд»¶зҡ„еёҒз§ҚгҖӮ</p>';target.innerHTML=`${renderSimpleThinkingSortControls()}<section><h3>зҺ°еӨҡжңҹз©ә</h3>${render(simpleThinkingCache.spot_simple)}</section><section><h3>жңҹеӨҡжңҹз©ә</h3>${render(simpleThinkingCache.dual_simple)}</section>`}
const openSymbolDetailBase=openSymbolDetail;window.openSymbolDetail=async function(symbol){await openSymbolDetailBase(symbol);const modal=byId('symbolDetailModal');if(!modal)return;const start=byId('detailFundingStart')?.value||'',end=byId('detailFundingEnd')?.value||'',data=await (await fetch(`/api/symbol-detail?symbol=${encodeURIComponent(symbol)}&start=${start}&end=${end}`)).json(),heading=[...modal.querySelectorAll('h3')].find(node=>node.textContent.includes('зҺ°иҙ§'));if(heading&&!modal.querySelector('.trend-detail'))heading.insertAdjacentHTML('beforebegin',`<h3>д»·ж јиө°еҠҝ</h3><div class="trend-detail">${trendPeriods.map(([key,label])=>`<span><b>${label}</b><em class="${changeClass(data.trends[key])}">${displayChange(data.trends[key])}</em></span>`).join('')}</div>`)};
