function detailMoney(value){const n=Number(value);if(!Number.isFinite(n))return 'вҖ”';if(Math.abs(n)>=1e9)return `$${(n/1e9).toFixed(2)}B`;if(Math.abs(n)>=1e6)return `$${(n/1e6).toFixed(2)}M`;return money(n)}
