async function openSymbolDetail(symbol){let modal=byId('symbolDetailModal');const priorStart=byId('detailFundingStart')?.value,priorEnd=byId('detailFundingEnd')?.value;if(!modal){document.body.insertAdjacentHTML('beforeend','<section id="symbolDetailModal" class="modal hidden"></section>');modal=byId('symbolDetailModal')}modal.classList.remove('hidden');modal.innerHTML='<div class="dialog symbol-detail-dialog"><button class="close" onclick="closeSymbolDetail()">Г—</button><p>жӯЈеңЁиҜ»еҸ–иҜҰжғ…вҖҰ</p></div>';const start=priorStart||new Date(Date.now()-7*86400000).toISOString().slice(0,10),end=priorEnd||new Date().toISOString().slice(0,10),data=await (await fetch(`/api/symbol-detail?symbol=${encodeURIComponent(symbol)}&start=${start}&end=${end}`)).json(),daily=Object.entries(data.funding_daily||{});modal.innerHTML=`<div class="dialog symbol-detail-dialog"><button class="close" onclick="closeSymbolDetail()">Г—</button><h2>${data.symbol} иҜҰжғ…</h2><h3>зҺ°иҙ§д»·ж ј</h3><div class="detail-grid">${detailRows(data.spot,[['дәӨжҳ“жүҖ','exchange'],['д»·ж ј','mid'],['24HйҮҸ','volume_24h']])}</div><h3>еҗҲзәҰд»·ж ј</h3><div class="detail-grid">${detailRows(data.futures,[['дәӨжҳ“жүҖ','exchange'],['д»·ж ј','mid'],['еҹәе·®','basis'],['жҢҒд»“','open_interest'],['24HйҮҸ','volume_24h']])}</div><h3>е…ұжҢҮдҝЎжҒҜ</h3><div class="index-detail">${data.binance_index_components.length?data.binance_index_components.map(item=>`${item.name||item.component||'жҲҗеҲҶ'} ${item.weight||item.proportion||''}`).join(' В· '):'Binance жҢҮж•°жҲҗеҲҶеҫ…еҗҢжӯҘ'}</div><h3>Binance иө„йҮ‘иҙ№</h3><div class="detail-dates"><input id="detailFundingStart" type="date" value="${start}"><input id="detailFundingEnd" type="date" value="${end}"><button onclick="openSymbolDetail('${data.symbol}')">жҹҘиҜў</button></div><div class="funding-columns"><div><b>жҜҸж—ҘжҖ»иө„иҙ№</b>${daily.map(([day,rate])=>`<span>${day}<em class="${changeClass(rate)}">${percent(rate)}</em></span>`).join('')||'жҡӮж— ж•°жҚ®'}</div><div><b>жҜҸдёҖжңҹиө„йҮ‘иҙ№</b>${data.funding.map(item=>`<span>${item.time}<em class="${changeClass(item.rate)}">${percent(item.rate)}</em></span>`).join('')||'жҡӮж— ж•°жҚ®'}</div></div><p class="funding-total">еҢәй—ҙжҖ»иө„иҙ№пјҡ<b class="${changeClass(data.funding_total)}">${percent(data.funding_total)}</b></p></div>`}
