function thoughtShort(text,max=170){const value=String(text||'жҡӮж— ');return value.length>max?value.slice(0,max)+'вҖҰ':value}
function thoughtMistakePanel(title,items,type){const list=(items&&items.length?items:['жҡӮж— йңҖиҰҒеҚ•зӢ¬ж Үи®°зҡ„еҒҸе·®гҖӮ']);return `<section class="thought-mistake ${type}"><h4>${title}</h4>${thoughtList(list)}</section>`}
function thoughtValidation(item){const validation=item.validation||{};return ['30m','1h','2h'].map(key=>{const row=validation[key]||{};return `<span>${key.toUpperCase()} <b class="${changeClass(row.price_change)}">д»· ${thoughtPercent(row.price_change)}</b><i>жҢҒд»“ ${thoughtPercent(row.oi_change)} В· дәәж•°жҜ” ${thoughtPercent(row.ratio_change)} В· CVD ${thoughtLarge(row.cvd)} В· йҮҸ ${thoughtLarge(row.volume)}</i></span>`}).join('')}
function toggleThoughtShot(id){byId(id)?.classList.toggle('hidden')}
const expandedThoughts=new Set();
function toggleThoughtRecord(id,button){const detail=byId(`thought-detail-${id}`);if(!detail)return;detail.classList.toggle('hidden');const opened=!detail.classList.contains('hidden');opened?expandedThoughts.add(id):expandedThoughts.delete(id);const label=button?.querySelector('em');if(label)label.textContent=opened?'ж”¶иө·':'еұ•ејҖ'}
function thoughtProfitLabel(item){if(item.trade_status==='е·Іе№ід»“')return `<span class="${changeClass(item.realized_profit_pct)}">е·Іе®һзҺ° ${thoughtPercent(item.realized_profit_pct)}</span>`;if(item.profit_pct!==null&&item.profit_pct!==undefined)return `<span class="${changeClass(item.profit_pct)}">жө®зӣҲ ${thoughtPercent(item.profit_pct)}</span>`;return `<span>иғңзҺҮ ${item.thesis_win_rate?.rate??0}%</span>`}
function thoughtSideClass(item){return item.trade_side==='еҒҡеӨҡ'?'long':(item.trade_side==='еҒҡз©ә'?'short':'watch')}
function thoughtSideBadge(item){return `<span class="thought-side-badge ${thoughtSideClass(item)}">${item.trade_side||'и§ӮеҜҹ'}</span>`}
function thoughtSummaryLine(item){const side=item.trade_side||'и§ӮеҜҹ',status=item.trade_status||'зӣҜзӣҳ',entry=item.entry!==null&&item.entry!==undefined?` В· е…Ҙеңә ${thoughtPrice(item.entry)}`:'';if(item.trade_status==='е·Іе№ід»“')return `${side} В· ${status}${entry} В· жӯўзӣҲ ${thoughtPrice(item.exit)} В· еҪ“еүҚ ${thoughtPrice(item.last)}`;return `${side} В· ${status}${entry} В· еҪ“еүҚ ${thoughtPrice(item.last)}`}
function thoughtCard(item){const id=item.symbol.replace(/[^A-Z0-9]/g,''),shotId=`thought-shot-${id}`,expanded=expandedThoughts.has(id);return `<article class="thought-card compact ${thoughtSideClass(item)}"><button type="button" class="thought-summary" onclick="toggleThoughtRecord('${id}',this)"><span><b>${item.symbol} ${thoughtSideBadge(item)}</b><i>${thoughtSummaryLine(item)}</i></span>${thoughtProfitLabel(item)}<strong>иғңзҺҮ ${item.thesis_win_rate?.rate??0}%</strong><em>${expanded?'ж”¶иө·':'еұ•ејҖ'}</em></button><div id="thought-detail-${id}" class="thought-detail ${expanded?'':'hidden'}"><div class="thought-card-head"><div><p class="eyebrow">ACTIVE REVIEW</p><h3>${item.symbol} жҖқи·ҜеӨҚзӣҳ ${thoughtSideBadge(item)}</h3><small>${item.trade_status||'зӣҜзӣҳ'} В· е…Ҙеңә ${thoughtPrice(item.entry)} В· еҪ“еүҚ ${thoughtPrice(item.last)} В· иғңзҺҮ ${item.thesis_win_rate?.rate??0}%</small></div><div class="thought-actions"><button type="button" class="shot-toggle" onclick="event.stopPropagation();toggleThoughtShot('${shotId}')">жҲӘеӣҫ</button><a class="kline-link" target="_blank" rel="noopener noreferrer" href="${coinglassKlineUrl(item.symbol)}" onclick="event.stopPropagation()">Kзәҝ</a></div></div>${item.screenshot_url?`<div id="${shotId}" class="thought-shot hidden"><img src="${item.screenshot_url}" alt="${item.symbol} CoinGlass ж•°жҚ®жҲӘеӣҫ"></div>`:''}<section class="thought-core"><h4>ж ёеҝғеҲӨж–ӯ</h4><p>${thoughtShort(item.thought_summary||item.my_thesis,220)}</p></section><div class="thought-two-col mistake-grid">${thoughtMistakePanel('дҪ зҡ„еҒҸе·® / йңҖиҰҒдҝ®жӯЈ',item.user_mistakes,'user')}${thoughtMistakePanel('жҲ‘зҡ„еӨұиҜҜ / и§„еҲҷдҝ®жӯЈ',item.assistant_mistakes,'assistant')}</div><section><h4>еҪ“еүҚйӘҢиҜҒ</h4><p>${thoughtShort(item.validation_view,220)}</p><div class="thought-validation">${thoughtValidation(item)}</div></section><div class="thought-two-col"><section><h4>жӯўзӣҲи®ЎеҲ’</h4>${thoughtList((item.take_profit||[]).slice(0,3))}</section><section><h4>жӯўжҚҹи®ЎеҲ’</h4>${thoughtList((item.stop_loss||[]).slice(0,3))}</section></div><section><h4>еӨҚзӣҳи®°еҪ•</h4>${thoughtList((item.review_notes||[]).slice(0,4))}</section><p class="thought-source">${item.thesis_win_rate?.note||''} В· ж•°жҚ®жқҘжәҗпјҡ${item.source==='live'?'Binance е…¬ејҖе®һж—¶жҺҘеҸЈ':'жң¬ең°еҝ«з…§йҷҚзә§'}гҖӮ</p></div></article>`}
async function loadThoughtAnalysis(){const target=byId('thoughtAnalysis');if(!target)return;if(!target.dataset.loaded&&!target.children.length)target.innerHTML='<p class="loading">жӯЈеңЁиҜ»еҸ–жҖқи·ҜеҲҶжһҗвҖҰ</p>';target.classList.add('soft-loading');try{const data=await (await fetch('/api/daily-report/thoughts')).json();target.dataset.loaded='1';target.innerHTML=data.items?.length?data.items.map(thoughtCard).join(''):'<p class="empty-alert">жҡӮж— жҖқи·ҜеҲҶжһҗи®°еҪ•гҖӮ</p>'}catch(error){if(!target.dataset.loaded)target.innerHTML='<p class="empty-alert">жҖқи·ҜеҲҶжһҗжҡӮж—¶ж— жі•иҜ»еҸ–гҖӮ</p>'}finally{target.classList.remove('soft-loading')}}
function fundingTrendRow(item){return `<article class="funding-trend-card ${item.level==='йҮҚзӮ№жңәдјҡ'?'hot':item.level==='йҮҚзӮ№зӣҜзӣҳ'?'watch':'observe'}"><div class="funding-trend-head"><div><b><button class="symbol-detail-trigger" onclick="openSymbolDetail('${item.symbol}')">${item.symbol}</button></b><span>${item.long_exchange} зҺ°иҙ§ вҶ’ Binance еҗҲзәҰ <em class="interval-badge ${intervalClass(item.funding_interval)}">${item.funding_interval||8}H</em></span></div><strong>${item.level}</strong><i>${Number(item.score||0).toFixed(1)}</i></div><div class="funding-trend-grid"><span>24Hж¶Ёе№… <b class="${changeClass(item.change_24h)}">${displayChange(item.change_24h)}</b></span><span>3Dж¶Ёе№… <b class="${changeClass(item.change_3d)}">${displayChange(item.change_3d)}</b></span><span>еҪ“еүҚиө„иҙ№ <b class="${changeClass(item.funding_current)}">${percent(item.funding_current)}</b></span><span>дёҠжңҹиө„иҙ№ <b class="${changeClass(item.funding_previous)}">${percent(item.funding_previous)}</b></span><span>24Hиө„иҙ№ <b class="${changeClass(item.funding_24h)}">${percent(item.funding_24h)}</b></span><span>3Dиө„иҙ№ <b class="${changeClass(item.funding_3d)}">${percent(item.funding_3d)}</b></span><span>еҹәе·® <b class="${changeClass(item.basis)}">${percent(item.basis)}</b></span><span>ејҖе·® <b class="${changeClass(item.open_spread)}">${percent(item.open_spread)}</b></span><span>12HжҢҒд»“еҸҳеҢ– <b class="${changeClass(item.oi_change_12h)}">${displayChange(item.oi_change_12h)}</b></span><span>12HйҮҸиғҪеҸҳеҢ– <b class="${changeClass(item.volume_change_12h)}">${displayChange(item.volume_change_12h)}</b></span><span>еҗҲзәҰжҢҒд»“ <b>${liquidityAmount(item.futures_open_interest)}</b></span><span>еҗҲзәҰдәӨжҳ“йҮҸ <b>${liquidityAmount(item.futures_volume)}</b></span></div></article>`}
async function loadFundingTrend(){const target=byId('fundingTrendList');if(!target)return;target.innerHTML='<p class="loading">жӯЈеңЁжү«жҸҸдё»еҚҮжӯЈиө„иҙ№жңәдјҡвҖҰ</p>';try{const data=await (await fetch('/api/arbitrage-thinking/funding-trend')).json();target.innerHTML=data.items?.length?`<p class="funding-trend-updated">жңҖиҝ‘жӣҙж–°пјҡ${data.updated_at||'вҖ”'} В· жҢүжңәдјҡиҜ„еҲҶжҺ’еәҸпјҢжҢҒд»“/дәӨжҳ“йҮҸеҸӘзңӢеўһй•ҝи¶ӢеҠҝдёҚеҒҡзЎ¬иҝҮж»ӨгҖӮ</p>${data.items.map(fundingTrendRow).join('')}`:'<p class="empty-alert">еҪ“еүҚжІЎжңүиҝӣе…Ҙдё»еҚҮжӯЈиө„иҙ№и§ӮеҜҹзҡ„еёҒз§ҚгҖӮ</p>'}catch(error){target.innerHTML='<p class="empty-alert">дё»еҚҮжӯЈиө„иҙ№жҰңжҡӮж—¶ж— жі•иҜ»еҸ–гҖӮ</p>'}}
document.querySelectorAll('nav a[data-view="daily-thoughts"]').forEach(link=>link.addEventListener('click',()=>loadThoughtAnalysis()));
updateSidebarSubnav(document.querySelector('.view.active')?.id||'dashboard');renderGainersShell();renderDualFuturesShell();addDualLiquidityHeader();addDualBasisSortControls();addBasisOpeningHeaders();installGroupFrameObservers();updateAlarmSoundButton();updateSortHeaders();updateDualSortHeaders();loadDashboard();loadStrategies();loadSpotFutures();loadDualFutures();loadAlerts(true);loadSimpleThinking();loadFundingTrend();loadThoughtAnalysis();loadTokenHedgeProfiles();setInterval(loadDashboard,5000);setInterval(loadSpotFutures,5000);setInterval(loadDualFutures,5000);setInterval(loadAlerts,5000);setInterval(loadSimpleThinking,30000);setInterval(loadFundingTrend,60000);setInterval(loadThoughtAnalysis,300000);
document.addEventListener('click',event=>{if(event.target.id==='symbolDetailModal')closeSymbolDetail()});
